import useAxios from 'axios-hooks';
import '../App.css';
// import { Component } from 'react';
import '../../node_modules/bootstrap/dist/css/bootstrap.css'
// import BootstrapTable from 'react-bootstrap-table-next';

function Sing() {
    const [{ data, loading, error }, refetch] = useAxios('http://127.0.0.1:5000/sings');

    if (loading) {
        return(
            <div className='loading'>
                <p>Загрузка данных...</p>
            </div>
        );
    }

    if (error) {
        return(
            <div className='error'>
                <p>Ошибка:</p>
                <p>{error.message}</p>
                <button onClick={() => refetch()}>
                    Повторный запрос
                </button>
            </div>
        );
    }

    let list_sings = JSON.stringify(data['items']);

    for (const element of list_sings.legth) {
        return (
            <>
            <p>{element['id']}</p>
            {/* <p>{element.id}</p> */}
            {/* <p>{element.name_sing}</p> */}
            </>
        )
    }
